var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 제가…… <color=#ffd34c>반드시 멸해야만 하는 악</color>?","JPN":"え？　私が……<color=#ffd34c>滅ぼすべき悪</color>？","ENG":"Me? <color=#ffd34c>The evil that must be destroyed</color>?","TWN":"什麼？我就是……<color=#ffd34c>該死的惡人</color>？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니, 그보다 숙부님이 돌아가셨다고요? 정말로요?","JPN":"いえ、それよりも叔父様がお亡くなりに？　本当ですか？","ENG":"Wait, did you just say Uncle is dead? Is that true?","TWN":"等等，你說叔叔死了？是真的嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그래! 사회 혼란을 우려해 홍보팀이 보도를 막고 있지만, 명명백백한 사실이야!","JPN":"そうだ！　広報チームが社会的混乱を危惧して報道を止めてるけど、\\n明々白々たる事実だ！","ENG":"Correct! The PR team is preventing the report from being released for fear of causing social uproar, but it is an undeniable fact!","TWN":"沒錯！公關部的人怕引起社會混亂，所以把報導擋下來，但這件事是千真萬確的！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그리고 감찰과는 이미 네가 끔찍한 범죄를 저질렀다는 증거와 증언까지 모두 확보했어!","JPN":"それに監察課は、お前の残酷な犯行を裏付ける証拠と証言をすべて確保してるから！","ENG":"Plus, Investigations has already collected indisputable evidence of your heinous crime!","TWN":"而監察科已經掌握你的犯罪證據和供詞！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"내 안의 <color=#ffd34c>파사의 목소리</color>도……. 네가 범인이라고 속삭이고 있다!","JPN":"私の中の<color=#ffd34c>破邪の声</color>も……お前が犯人だと囁いている！","ENG":"Even the <color=#ffd34c>Voice of Evil Eradication</color> within me... He whispers that you’re the culprit!","TWN":"我裡面的<color=#ffd34c>破邪之聲</color>……也說你是就是犯人！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"짜잔.","JPN":"ババン。","ENG":"Kachow!","TWN":"鏘鏘。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……파사의 목소리라고? 그건 뭐지?","JPN":"……破邪の声だって？　それはなんだ？","ENG":"The Voice of Evil Eradication? What’s that?","TWN":"……破邪之聲？那是什麼東東？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"뭐야? 너도 모르는 설정이야?","JPN":"えっ？　自分でもわからない設定なわけ？","ENG":"Huh? You don’t know the set-up either?","TWN":"你也不知道喔？這些台詞不是你們一起寫的嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"설정이라니! 그 무슨 망발이냐!","JPN":"設定だなんて！　失敬ではないか！","ENG":"Set-up?! What are you talking about?!","TWN":"什麼台詞！胡說八道什麼！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"더 이상의 저항은 소용없다! 신지아 대표와 그 졸개들!","JPN":"これ以上抵抗しても無駄だよ！　ヒメノ代表とその手下ども！","ENG":"Shin Jia and her henchmen! There’s no use in resisting!","TWN":"無須再抵抗！沈佳代表和你們這群小跟班！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"순순히 항복하지 않는다면 힘으로라도 데려가겠어!","JPN":"大人しく降伏しないなら、力づくで連れてくよ！","ENG":"Surrender now, or I will take you in by force!","TWN":"乖乖地投降吧！否則別怪我不客氣！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니요. 저는…….","JPN":"いえ、私は……","ENG":"No, I…","TWN":"等一下，我……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"자, 잠깐! 리더는 어젯밤에 우리랑 같이 전철을 타고 돌아왔다고!","JPN":"ちょ、ちょっと待って！　リーダーは昨夜、私たちと一緒に電車で帰ってきたの！","ENG":"H-hold it! Leader took the subway with us back home last night!","TWN":"先等等！老大昨天晚上是和我們一起搭地鐵回來的！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"처음 타 본다고 찍은 기념사진도 있단 말이야!","JPN":"初めて電車に乗るってことで、記念写真まで撮ったんだから！","ENG":"We even took a selfie to commemorate her first ride!","TWN":"老大說她是第一次搭地鐵，所以我們還有拍照留念呢！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"진짜?","JPN":"本当に？","ENG":"Is this true?","TWN":"真的嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"아, 아니지. 사진 같은 건 조작할 수 있다고 했어. 하마터면 속을 뻔했네.","JPN":"い、いや。写真は偽造もできるって言ってた。危うく騙されるとこだった。","ENG":"On second thought, no. Anyone can fake a photo. You almost got me there.","TWN":"不…不對！照片這種東西是可以偽造的吧？！差點上當！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"잘 들어, 버섯 머리. 이 범죄는 최소 한 명 이상의 공범이 가담한 정황이 있어.","JPN":"よーく聞いて、マッシュルーム。この犯罪は、最低でも一人以上の共犯者がいるとわかる状況証拠がある。","ENG":"Listen carefully, mushroom head. We already have information that at least one co-conspirator is involved.","TWN":"你給我聽好了，香菇頭！這次的犯罪事件，我們推測有超過一個以上的共犯！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"이사회 할아버지들이 그러니까 신지아 대표와 관련 있는 인물은 모두 신병을 확보해야 한다고…….","JPN":"だから、理事会のおじいさんたちは、ヒメノ代表に関わる人物は\\n全員身柄を確保する必要があると……","ENG":"The gramps on the board of directors said... that we need to capture everyone who’s connected with Shin Jia...","TWN":"所以董事會爺爺們說，沈佳代表和一切相關人士，全都要抓回去審問……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"하하하하하핫!!!","JPN":"ハハハハハハッ！！","ENG":"Hahahahaha!!!","TWN":"哈哈哈哈哈！！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"갑자기 뭐야, 준? 왜 웃는 건데?","JPN":"いきなり何よ、ジュン。なんで笑うの？","ENG":"Why’re you laughing, Jun?","TWN":"朱恩，你幹嘛？笑什麼笑？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"주리여. 그대가 파사의 길을 걷는 각오는 겨우 그 정도였나.","JPN":"ジュリー、破邪の道を歩む君の覚悟はその程度だったのか。","ENG":"Is that all you have in your determination to eradicate evil, Juri?","TWN":"朱莉，你那個想踏上破邪之路的決心不過如此而已嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんだって？","ENG":"W-what?","TWN":"什…什麼意思？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"대장이 부회장을 살해했다는 명명백백한 증언과 증거라는 건…….","JPN":"隊長が副会長を殺害したという明々白々な証言や証拠というのは……","ENG":"The evidence that you talk about linking Cap to the murder of the Vice Chairman...","TWN":"你說你們已經掌握隊長殺害副會長的證據和供詞……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"물론 직접 발로 뛰어 확보한 것이겠지?","JPN":"もちろん、自分の足で探し回って確保したんだろうな？","ENG":"I’m sure you collected it yourself, correct?","TWN":"這些證據和供詞，應該是你們親自調查到的吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"다른 누군가가 손에 쥐어 준 것이 아니라?","JPN":"誰かが君の手に握らせたわけではなく？","ENG":"And not have it handed to you by someone else, hmm?","TWN":"不是從誰那裡聽來的第二手消息吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"읏……!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"唔……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그, 그건!!","JPN":"そ、それは！！","ENG":"Th-that’s!!","TWN":"那…那是！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"다른 누군가가 시키는 대로 따르는 게 파사의 길이라고 생각했나?","JPN":"誰かに言われるがままに従うのが破邪の道だと思ったのか？","ENG":"Or did you think doing as you’re told was the path to eradicate evil?","TWN":"你認為破邪之路，就是對某人的命令言聽計從嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"실망스럽군, 동생이여.","JPN":"がっかりだな、妹よ。","ENG":"I’m disappointed in you, little sister.","TWN":"我對你太失望了，妹妹。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그, 그럼 준 너는 신지아 대표가 범인이 아니라고 확신할 수 있어?!","JPN":"じゃ、じゃあ、ジュンはヒメノ代表が犯人じゃないって確信できるの！？","ENG":"Th-then Jun...! How are you so sure Shin Jia isn’t the culprit?!","TWN":"那你說說看，你能確定沈佳代表不是犯人嗎？！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"동료들도 믿지 못하면서 어떻게 사나이를 자처하겠는가!","JPN":"男たるもの、仲間を信頼して当然だ！","ENG":"A real man doesn’t suspect his mates, he trusts them!","TWN":"不信任夥伴的話，還算什麼男子漢！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"설령 그 때문에 범죄자 취급을 받는다고 하더라도, 내 한 점 후회는 없다!","JPN":"たとえそのせいで自分が共犯者扱いされたとしても、後悔はない！","ENG":"Even if it means being treated like a criminal, I have no regrets!","TWN":"就算因此被視為犯人，我也絕不會後悔！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……빠밤.","JPN":"……ジャジャン。","ENG":"...Kapow!","TWN":"……噠啦！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"크읏!!","JPN":"くうっ！！","ENG":"Gah!!","TWN":"可惡！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"가브리엘 씨…….","JPN":"ガブリエルさん……","ENG":"Gabriel...","TWN":"加布里埃爾……"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"역시 원조는 달라! 멋진 소리도 할 줄 알잖아!","JPN":"さすが元祖は違うね！　決め台詞もばっちりだし！","ENG":"Looks like you can beat the copy thing! You sounded so cool just now!","TWN":"正版的果然不一樣！沒想到你也會說人話！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"원조나 짝퉁이나 귀찮은 타입이지만.","JPN":"本物も偽物も、面倒なのは一緒ですが。","ENG":"But still, both are kinda annoying to be honest...","TWN":"不過不管是正版還是山寨版都滿煩的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"으으……!","JPN":"うう……！","ENG":"Eergh...!!","TWN":"呃……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"준은 치사해! 치사하다구!","JPN":"ジュンはズルい！　ズルいよ！","ENG":"Not fair, Jun! Not! Fair!","TWN":"朱恩你好奸詐！過份！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"갑자기 나 혼자 두고 없어져 놓고선! 왜 대표 편만 드는 건데!","JPN":"急に消えて私をひとりぼっちにしたくせに！　どうして代表の肩ばかり持つの？","ENG":"You left me all of a sudden! And now you take her side?!","TWN":"扔下我自己一個人跑掉！現在還幫代表說話！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"도, 동생이여. 그건 어디까지나 사명을 이루기 위해…….","JPN":"い、妹よ。それはあくまで使命を果たすためで……","ENG":"M-my little sister... That was to heed my calling...","TWN":"妹妹…就某部分來說，我是因為要完成使命……"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그리고 그 동생이란 말!","JPN":"それに、その妹って呼び方！","ENG":"And about the little sister!","TWN":"你還敢叫我妹妹！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"잊진 않았겠지, 준? 지난날 우리가 했던 약속을!","JPN":"忘れてないよね、ジュン？　かつて私たちが交わした約束を！","ENG":"You didn’t forget our promise now, did you Jun?!","TWN":"你沒忘記吧？我們之前的約定！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……물론이지. 기억하고 있다, 주리.","JPN":"……もちろん。ちゃんと覚えているよ、ジュリー。","ENG":"...Of course. I remember, Juri.","TWN":"……我當然沒忘，朱莉。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"태어난 순서와 관계없이 <color=#ffd34c>싸워서</color> 진 쪽이 아우가 되기로.","JPN":"生まれた順とは関係なく、<color=#ffd34c>勝負して</color>負けた方が下になるって。","ENG":"We decided that we’d <color=#ffd34c>fight</color> and the loser would become the younger sibling.","TWN":"不管是誰先出生的，只要<color=#ffd34c>打架</color>輸的一方就要做小的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"원한다면 언제든 도전해라. 누가 위인지 확실히 새겨 주지.","JPN":"望むならいつでも挑戦を受けるとも。\\nどちらが上なのか、ハッキリわからせてやろう。","ENG":"You’re welcome to challenge me anytime. I’ll show you who’s boss.","TWN":"歡迎你隨時來挑戰，我會讓你知道誰才是老大。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"좋아! 나도 바라는 바라구, 준!","JPN":"よし！　私も望むところだよ、ジュン！","ENG":"Okay! That’s all I needed to hear, Jun!","TWN":"很好！正如我所願，朱恩！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"가브리엘 씨, 그만두세요. 가족끼리 싸우면 안 돼요.","JPN":"ガブリエルさん、おやめください。家族同士でケンカはよくないですよ。","ENG":"Gabriel, please don’t fight. Family shouldn’t fight each other.","TWN":"加布里埃爾，不要這樣，家人之間怎麼可以打架呢！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 저건 시간을 벌기 위한 도발이에요, 리더. ","JPN":"いいえ。あれは時間稼ぎのための挑発です、リーダー。","ENG":"No, Leader. This is a ruse to buy time.","TWN":"不，老大，加布里埃爾這麼做是在為我們爭取時間。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"저렇게 쉽게 걸려들다니 답도 없는 팔랑귀네요.","JPN":"あんな風にまんまと引っかかるなんて、とんでもなくチョロいですね。","ENG":"Hook, line, and sinker. Can’t believe anyone could be this gullible.","TWN":"只是沒想到對方這麼輕易就上鉤。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그렇다, 대장. 내가 여기서 동생을 잡아 두는 동안 실장에게 가라.","JPN":"そうだ、隊長。私がここで妹の足止めをしている間に室長のもとに行け。","ENG":"That’s right, Cap. While I keep my little sister busy, you should go find Chief.","TWN":"沒錯，隊長。趁我和妹妹打架的時候，你快去找室長！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니에게요?","JPN":"ホノカさんのところに？","ENG":"You want me to go to Jin?","TWN":"去找李珍姐嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"가브리엘 말이 맞아! 실장님이라면 오해를 풀 수 있을 거야!","JPN":"ガブリエルの言うとおりだよ！　室長なら誤解を解いてくれるはずだから！","ENG":"Gabriel’s right! I’m sure Chief will know how to resolve this!","TWN":"加布里埃爾說的沒錯！室長一定可以解開誤會的！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"다른 감찰부 사람들은 내가 막을게. 리더는 초원이랑 같이 실장님을 찾아가.","JPN":"他の監察課の人たちは私が止めるよ。\\nリーダーはナオと一緒に室長を探しに行って。","ENG":"I’ll hold off the rest of Investigations. Leader, you should go find Chief with Chowon.","TWN":"其他監察科的人就交給我，老大你快和初源去找室長！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"소녀와 함께하는 건 마음에는 안 들지만……. 동생이 상대라면 어쩔 수 없군.","JPN":"少女とともに行動するのは気が進まないが……妹相手なら仕方ない。","ENG":"It irritates me to battle alongside you, girl... But I guess I have no choice when it’s my little sister we’re up against.","TWN":"雖然我不是很想和少女一起……但因為對手是妹妹，也只能如此。"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"두 분……. 정말 괜찮으시겠어요?","JPN":"皆さん……本当によろしいのでしょうか。","ENG":"Both of you... Are you sure you’ll be okay?","TWN":"你們……真的沒問題嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그럼! 오늘은 이 녀석이랑 내가 더블 카운터니까!","JPN":"任せて！　今日はこいつと私でダブルカウンターよ！","ENG":"Of course! Him and I together, we’re Double Counter!","TWN":"當然！今天我和那傢伙是制裁者二人組！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훗. 오늘 한 번은 그 장단에 어울려 주지.","JPN":"フッ、今日くらいはそのノリに合わせてやるか。","ENG":"Hmph! I’ll allow it this one time.","TWN":"呵，今天我就稍微配合你吧！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……알겠어요.","JPN":"……わかりました。","ENG":"...Okay.","TWN":"……好吧！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"꼭 오해를 풀고 올게요! 두 분 다 다치시면 안 돼요!","JPN":"必ず誤解を解いてみせます！　お二人ともケガしないでくださいね！","ENG":"I’ll get to the bottom of this! Don’t get hurt! The both of you!","TWN":"我會盡快將誤會解開！你們千萬要小心，不要受傷喔！"},"stage":{"bg":"OFFICE_MESSED","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};